 29→/** Contains all runtime parameters and results. No functionality just
 30→ * bookkeeping.*/
 31→class Parameters {
 32→
 33→public:
 34→  Parameters();
 35→  ~Parameters() = default;
 36→  // TODO: Is this complete?
 37→  Parameters(const Parameters &) = default;
 38→  int load(string filename);
 39→  int load(FILE *file);
 40→
 41→  /** string constants: declared here, defined in Parameters.cpp. **/
 42→
 43→  // potentials //
 44→  // jobs //
 45→
 46→  // Physical Constants
 47→  double kB;
 48→  double timeUnit;
 49→
 50→  /** input parameters **/
 51→
 52→  // [Main] //
 53→  JobType job;
 54→  long randomSeed;
 55→  double temperature;
 56→  bool quiet;
 57→  bool writeLog;
 58→  bool checkpoint;
 59→  string iniFilename;
 60→  string conFilename;
 61→  double finiteDifference;
 62→  long maxForceCalls;
 63→  bool removeNetForce;
 64→
 65→  // [Potential] //
 66→  PotType potential;
 67→  double MPIPollPeriod;
 68→  bool LAMMPSLogging;
 69→  int LAMMPSThreads;
 70→  bool EMTRasmussen;
 71→  bool LogPotential;
 72→  string extPotPath;
 73→
 74→  // [AMS] and [AMS_IO] //
 75→  struct ams_options_t {
 76→    string engine;     // MOPAC, ADF, BAND, REAXFF, FORCEFIELD
 77→    string forcefield; // OPt.ff etc. (REAXFF)
 78→    string model;      // Model hamiltonian (MOPAC)
 79→    string resources;  // DFTB
 80→    string xc;         // Exchange (BAND, ADF)
 81→    string basis;      // Basis (BAND, ADF)
 82→    struct env_t {
 83→      string amshome;
 84→      string scm_tmpdir;
 85→      string scmlicense;
 86→      string scm_pythondir;
 87→      string amsbin;
 88→      string amsresources;
 89→    } env;
 90→  } ams_options;
 91→
 92→  // [XTBPot] //
 93→  struct xtb_options_t {
 94→    string paramset;
 95→    double elec_temperature;
 96→    size_t maxiter;
 97→    double acc;
 98→    double charge;
 99→    int uhf;
100→  } xtb_options;
101→
102→  // [ZBLPot] //
103→  struct zbl_options_t {
104→    double cut_inner;
105→    double cut_global;
106→  } zbl_options;
107→
108→  // [SocketNWChemPot] //
109→  struct socket_nwchem_options_t {
110→    std::string host;
111→    int port;
112→    int mem_in_gb;
113→    std::string nwchem_settings;
114→    std::string unix_socket_path;
115→    bool unix_socket_mode;
116→    bool make_template_input;
117→  } socket_nwchem_options;
118→
119→  // [Structure Comparison] //
120→  struct structure_comparison_options_t {
121→    double distance_difference;
122→    double neighbor_cutoff;
123→    bool check_rotation;
124→    bool indistinguishable_atoms;
125→    double energy_difference;
126→    bool remove_translation;
127→  } structure_comparison_options;
128→
129→  // [Process Search] //
130→  struct process_search_options_t {
131→    bool minimize_first;
132→    double minimization_offset;
133→  } process_search_options;
134→
135→  // [Saddle Search] //
136→  struct saddle_search_options_t {
137→    long max_jump_attempts;
138→    long max_iterations;
139→    string method;
140→    string minmode_method;
141→    string displace_type;
142→    double max_energy;
143→    double displace_magnitude;
144→    double max_single_displace;
145→    double displace_radius;
146→    double converged_force;
147→    double perp_force_ratio;
148→    bool nonnegative_displacement_abort;
149→    long nonlocal_count_abort;
150→    double nonlocal_distance_abort;
151→    bool remove_rotation;
152→    double zero_mode_abort_curvature;
153→    struct dynamics_t {
154→      double temperature;
155→      double state_check_interval_input;
156→      double state_check_interval;
157→      double record_interval_input;
158→      double record_interval;
159→      bool linear_interpolation;
160→      double max_init_curvature;
161→    } dynamics;
162→    struct confine_positive_t {
163→      bool enabled;
164→      bool bowl_breakout;
165→      long bowl_active;
166→      double min_force;
167→      double scale_ratio;
168→      double boost;
169→      long min_active;
170→    } confine_positive;
171→  } saddle_search_options;
172→
173→  // [Optimizer] //
174→  OptType optMethod;
175→  OptType refineOptMethod;     // used below refine threshold
176→  double refineThreshold;      // threshold to switch opt_method
177→  string optConvergenceMetric; // norm, max_atom, max_component
178→  string optConvergenceMetricLabel;
179→  size_t optMaxIterations; // maximum iterations for saddle point searches and
180→                           // minimization
181→  double
182→      optMaxMove; // maximum displacement vector for a step during optimization
183→  double optConvergedForce; // force convergence criterion required for an
184→                            // optimization
185→  double optTimeStepInput;
186→  double optTimeStep;         // time step size used in quickmin
187→  double optMaxTimeStepInput; // maximum time step for FIRE.
188→  double optMaxTimeStep;      // maximum time step for FIRE.
189→  long optLBFGSMemory; // number of previous forces to keep in the bfgs memory
190→  double optLBFGSInverseCurvature;
191→  double optLBFGSMaxInverseCurvature;
192→  bool optLBFGSAutoScale;
193→  bool optLBFGSAngleReset;
194→  bool optLBFGSDistanceReset;
195→  bool optQMSteepestDecent; // if set the velocity will always be set to zero in
196→                            // quickmin
197→  bool optCGNoOvershooting; // if set it is ensured that the approximate line
198→                            // search in conjugate gradients never overshoot the
199→                            // minimum along the search line
200→  bool
201→      optCGKnockOutMaxMove; // if set the old search direction is nullified when
202→                            // steps larger than the optMaxMove are conducted
203→  bool optCGLineSearch;     // if set full line search is conducted
204→  double optCGLineConverged;    // convergence criteria for line search, ratio
205→                                // between force component along search line and
206→                                // the orthogonal part
207→  long optCGLineSearchMaxIter;  // maximal nr of iterations during line search
208→  long optCGMaxIterBeforeReset; // max nr of cg steps before reset, if 0 no
209→                                // resetting is done
210→  double optSDAlpha;
211→  bool optSDTwoPoint;
212→
213→  // [Dimer] //
214→  struct dimer_options_t {
215→    double rotation_angle;
216→    bool improved;
217→    double converged_angle;
218→    long max_iterations;
219→    string opt_method;
220→    long rotations_max;
221→    long rotations_min;
222→    double torque_max;
223→    double torque_min;
224→    bool remove_rotation;
225→  } dimer_options;
226→
227→  // [GPR Dimer] //
228→  struct gpr_dimer_options_t {
229→    double rotation_angle;
230→    double converged_angle;
231→    double relax_conv_angle;
232→    long init_rotations_max;
233→    long relax_rotations_max;
234→    long divisor_t_dimer_gp;
235→    long max_outer_iterations;
236→    long max_inner_iterations;
237→    double midpoint_max_disp;
238→    string rot_opt_method;
239→    string trans_opt_method;
240→    double active_radius;
241→    double dimer_sep;
242→    double conv_step;
243→    double max_step;
244→    double ratio_at_limit;
245→    bool init_rot_gp;
246→    bool init_trans_gp;
247→    bool many_iterations;
248→    struct gpr_params_t {
249→      string hyper_opt_method;
250→      double sigma2;
251→      double jitter_sigma2;
252→      double noise_sigma2;
253→      double prior_mu;
254→      double prior_sigma2;
255→      long prior_nu;
256→    } gpr_params;
257→    struct opt_params_t {
258→      bool check_derivatives;
259→      int max_iterations;
260→      double tol_func;
261→      double tol_sol;
262→      long lambda_limit;
263→      long lambda_init;
264→    } opt_params;
265→    struct prune_params_t {
266→      bool use_prune;
267→      int begin;
268→      int n_vals;
269→      double threshold;
270→    } prune_params;
271→    struct debug_params_t {
272→      int report_level;
273→      int debug_level;
274→      string out_dir;
275→      string pos_file;
276→      string energy_file;
277→      string grad_file;
278→      string out_ext;
279→      double offset_mid_point;
280→      double dy;
281→      double dz;
282→    } debug_params;
283→  } gpr_dimer_options;
284→
285→  // [GP Surrogate] //
286→  struct gp_surrogate_options_t {
287→    bool enabled;
288→    JobType sub_job;
289→    double uncertainty;
290→    bool linear_path_always;
291→    PotType potential;
292→  } gp_surrogate_options;
293→
294→  // [CatLearn] //
295→  struct catlearn_options_t {
296→    std::string path;
297→    std::string model;
298→    std::string prior;
299→    bool use_deriv;
300→    bool use_fingerprint;
301→    bool parallel;
302→  } catlearn_options;
303→
304→  // [ASE_ORCA] //
305→  struct ase_orca_options_t {
306→    std::string path;
307→    std::string nproc;
308→    std::string simpleinput;
309→  } ase_orca_options;
310→
311→  // [ASE_NWCHEM] //
312→  struct ase_nwchem_options_t {
313→    std::string path;
314→    std::string nproc;
315→    std::string multiplicity;
316→    double scf_thresh;
317→    long scf_maxiter;
318→  } ase_nwchem_options;
319→
320→  // [Metatomic] //
321→  struct metatomic_options_t {
322→    std::string model_path;  // Path to the TorchScript model file.
323→    std::string device;      // "cpu", "cuda", "mps", or empty to auto-detect.
324→    std::string length_unit; // The unit of length used in the simulation (e.g.,
325→                             // "angstrom").
326→    std::string extensions_directory; // Path for TorchScript extensions.
327→    bool check_consistency;           // To enable model's internal checks.
328→    double uncertainty_threshold;     // Threshold for uncertainty reporting.
329→                                      // also used to populate the variance
330→                                      // -1 to disable, 100meV/atom default
331→    struct variants_t {
332→      std::string base;               // global key for energy and forces
333→      std::string energy;             // override for energy variant
334→      std::string energy_uncertainty; // override for variant on the
335→                                      // energy uncertainty
336→    } variant;
337→  } metatomic_options;
338→
339→  // [Lanczos] //
340→  struct lanczos_options_t {
341→    double tolerance;
342→    long max_iterations;
343→    bool quit_early;
344→  } lanczos_options;
345→
346→  // [Prefactor] //
347→  struct prefactor_options_t {
348→    double default_value;
349→    double max_value;
350→    double min_value;
351→    double within_radius;
352→    double min_displacement;
353→    string rate;
354→    string configuration;
355→    bool all_free_atoms;
356→    string filter_scheme;
357→    double filter_fraction;
358→  } prefactor_options;
359→
360→  // [Hessian] //
361→  struct hessian_options_t {
362→    string atom_list;
363→    double zero_freq_value;
364→  } hessian_options;
365→
366→  // [Nudged Elastic Band] //
367→  struct neb_options_t {
368→    // Core parameters for the chain-of-states simulation
369→    long image_count;    // Number of replicas along the reaction coordinate
370→    long max_iterations; // Maximum steps for the path optimization
371→    OptType opt_method; // Optimization algorithm (e.g., QuickMin, FIRE, L-BFGS)
372→    double
373→        force_tolerance; // Convergence criterion for the root-mean-square force
374→    struct mmf_peak_options_t {
375→      bool enabled;     // Initialize mode estimates for each peak
376→      double tolerance; // Cutoff for generating peaks
377→    } mmf_peaks;
378→
379→    struct spring_options_t {
380→      double constant;       // The spring constant (k) connecting images
381→      bool use_elastic_band; // Toggle for the elastic band projection
382→      bool doubly_nudged;    // Inclusion of the perpendicular spring force
383→                             // components
384→      bool use_switching;    // Switching function for doubly nudged NEB
385→
386→      struct energy_weighting_t {
387→        bool
388→            enabled; // Adjusts spring constants based on image potential energy
389→        double trigger; // Threshold to activate energy weighted springs
390→        double k_min;   // Minimum spring constant for low-energy regions
391→        double k_max; // Maximum spring constant for high-energy barrier regions
392→      } weighting;
393→      struct onsager_machlup_t {
394→        bool enabled; // Main toggle for OM-NEB
395→
396→        // Adaptive Spring Constant Logic
397→        bool optimize_k; // Re-calculate k_om every step?
398→        double k_scale;  // Scaling factor for the heuristic (dimensionless)
399→
400→        // Optional: Safety bounds to prevent numerical explosions
401→        double k_min;
402→        double k_max;
403→      } om;
404→    } spring;
405→
406→    struct climbing_image_options_t {
407→      bool enabled; // Enables the Climbing Image (CI-NEB) modification
408→      bool
409→          converged_only; // Wait for initial MEP convergence before starting CI
410→      bool use_old_tangent;  // Algorithm choice for the local tangent estimate
411→      double trigger_force;  // Force threshold to activate the CI-NEB algorithm
412→      double trigger_factor; // relative factor
413→
414→      struct hybrid_dimer_t {
415→        bool use_mmf; // Integrates Min-Mode Following (MMF) for saddle point
416→                      // refinement
417→        double trigger_force; // Force threshold to activate hybrid dimer search
418→        long max_steps;       // Maximum steps for the MMF refinement phase
419→        long ci_stability_count; // Number of stable iterations before settling
420→                                 // on a CI for MMF
421→        double angle_tol;        // Angular tolerance for the dimer rotation
422→        double trigger_factor;   // relative factor
423→        struct roneb_penalty_t {
424→          // penalty_factor = base + (strength * alignment);
425→          // std::abs(finalMode.normalized().dot(currentTangent.normalized()))
426→          double strength; // amount by which the threshold is reduced
427→          double base;     // baseline
428→        } penalty;
429→      } roneb;
430→    } climbing_image;
431→
432→    struct path_initialization_t {
433→      NEBInit method; // Method for generating the initial guess (e.g., IDPP)
434→      std::string
435→          input_path;     // Path to a file containing initial image coordinates
436→      int max_iterations; // Maximum iterations for the path pre-optimizer
437→      int nsteps;         // Iterations for the path pre-optimizer
438→      double max_move;    // Maximum displacement per step during initialization
439→      double force_tolerance; // Convergence criterion for the initial path
440→                              // generation
441→      double sidpp_alpha; // Growth parameter for Steepest Intensity Decent Path
442→                          // Probing
443→      OptType opt_method; // for the IDPP
444→      bool oversampling;
445→      int oversampling_factor;
446→    } initialization;
447→
448→    struct endpoint_options_t {
449→      bool minimize; // Flag to optimize the reactant and product geometries
450→                     // first
451→      bool use_path_file; // Pull endpoint geometries from the initial path file
452→    } endpoints;
453→
454→  } neb_options;
455→
456→  // [Molecular Dynamics] //
457→  struct dynamics_options_t {
458→    double time_step_input;
459→    double time_step;
460→    double time_input;
461→    double time;
462→    long steps;
463→  } dynamics_options;
464→
465→  // [Parallel Replica] //
466→  struct parallel_replica_options_t {
467→    bool refine_transition;
468→    bool auto_stop;
469→    bool dephase_loop_stop;
470→    double dephase_time_input;
471→    double dephase_time;
472→    long dephase_loop_max;
473→    double state_check_interval_input;
474→    double state_check_interval;
475→    double record_interval_input;
476→    double record_interval;
477→    double corr_time_input;
478→    double corr_time;
479→  } parallel_replica_options;
480→
481→  // [Temperature Accelerated Dynamics] //
482→  struct tad_options_t {
483→    double low_temperature;
484→    double min_prefactor;
485→    double confidence;
486→  } tad_options;
487→
488→  // [Thermostat] //
489→  struct thermostat_options_t {
490→    string kind;
491→    double andersen_alpha;
492→    double andersen_tcol_input;
493→    double andersen_tcol;
494→    double nose_mass;
495→    double langevin_friction_input;
496→    double langevin_friction;
497→  } thermostat_options;
498→
499→  // [Replica Exchange] //
500→  struct replica_exchange_options_t {
501→    string temperature_distribution;
502→    long replicas;
503→    long exchange_trials;
504→    double sampling_time_input;
505→    double sampling_time;
506→    double temperature_high;
507→    double temperature_low;
508→    double exchange_period_input;
509→    double exchange_period;
510→  } replica_exchange_options;
511→
512→  // [Bond Boost / Hyperdynamics] //
513→  struct hyperdynamics_options_t {
514→    string bias_potential;
515→    string boost_atom_list;
516→    double rmd_time_input;
517→    double rmd_time;
518→    double dvmax;
519→    double qrr;
520→    double prr;
521→    double qcut;
522→  } hyperdynamics_options;
523→
524→  // [Basin Hopping] //
525→  struct basin_hopping_options_t {
526→    double displacement;
527→    double initial_random_structure_probability;
528→    double push_apart_distance;
529→    long steps;
530→    long quenching_steps;
531→    bool significant_structure;
532→    bool single_atom_displace;
533→    string displacement_algorithm;
534→    string displacement_distribution;
535→    double swap_probability;
536→    long jump_max;
537→    long jump_steps;
538→    bool adjust_displacement;
539→    long adjust_period;
540→    double adjust_fraction;
541→    double target_ratio;
542→    bool write_unique;
543→    double stop_energy;
544→  } basin_hopping_options;
545→
546→  // [Global Optimization] //
547→  struct global_optimization_options_t {
548→    string move_method;
549→    string decision_method;
550→    long steps;
551→    double beta;
552→    double alpha;
553→    long mdmin;
554→    double target_energy;
555→  } global_optimization_options;
556→
557→  // [Monte Carlo] //
558→  struct monte_carlo_options_t {
559→    double step_size;
560→    int steps;
561→  } monte_carlo_options;
562→
563→  // [BGSD] //
564→  struct bgsd_options_t {
565→    double alpha;
566→    double beta;
567→    double gradient_finite_difference;
568→    double h_force_convergence;
569→    double grad2energy_convergence;
570→    double grad2force_convergence;
571→  } bgsd_options;
572→
573→  // MPI stuff, not actually specified in config file
574→  // it is used to pass information to the GPAW MPI potential.
575→  int MPIPotentialRank;
576→#ifdef EONMPI
577→  MPI_Comm MPIClientComm;
578→#endif
579→
580→  // [Debug] //
581→  struct debug_options_t {
582→    bool write_movies;
583→    long write_movies_interval;
584→    bool estimate_neb_eigenvalues;
585→    string neb_mmf;
586→  } debug_options;
587→
588→private:
589→  string toLowerCase(string s);
590→};
