 487→int Parameters::load(FILE *file) {
 488→
 489→  CIniFile ini;
 490→  ini.CaseInsensitive();
 491→  int error = 0;
 492→
 493→  if (ini.ReadFile(file)) {
 494→
 495→    // [Main] //
 496→
 497→    job = magic_enum::enum_cast<JobType>(ini.GetValue("Main", "job"),
 498→                                         magic_enum::case_insensitive)
 499→              .value_or(JobType::Unknown);
 500→    temperature = ini.GetValueF("Main", "temperature", temperature);
 501→    randomSeed = ini.GetValueL("Main", "random_seed", randomSeed);
 502→    checkpoint = ini.GetValueB("Main", "checkpoint", checkpoint);
 503→    quiet = ini.GetValueB("Main", "quiet", quiet);
 504→    writeLog = ini.GetValueB("Main", "write_log", writeLog);
 505→    finiteDifference =
 506→        ini.GetValueF("Main", "finite_difference", finiteDifference);
 507→    // Initialize random generator
 508→    if (randomSeed < 0) {
 509→      unsigned i = time(NULL);
 510→      randomSeed = i;
 511→      helper_functions::random(i);
 512→    } else {
 513→      helper_functions::random(randomSeed);
 514→    }
 515→    maxForceCalls = ini.GetValueL("Main", "max_force_calls", maxForceCalls);
 516→    removeNetForce = ini.GetValueB("Main", "remove_net_force", removeNetForce);
 517→
 518→    // [Potential] //
 519→
 520→    potential =
 521→        magic_enum::enum_cast<PotType>(ini.GetValue("Potential", "potential"),
 522→                                       magic_enum::case_insensitive)
 523→            .value_or(PotType::UNKNOWN);
 524→    MPIPollPeriod =
 525→        ini.GetValueF("Potential", "mpi_poll_period", MPIPollPeriod);
 526→    LAMMPSLogging = ini.GetValueB("Potential", "lammps_logging", LAMMPSLogging);
 527→    LAMMPSThreads =
 528→        (int)ini.GetValueL("Potential", "lammps_threads", LAMMPSThreads);
 529→    EMTRasmussen = ini.GetValueB("Potential", "emt_rasmussen", EMTRasmussen);
 530→    extPotPath = ini.GetValue("Potential", "ext_pot_path", extPotPath);
 531→
 532→    if (potential == PotType::MPI || potential == PotType::VASP ||
 533→        potential == PotType::BOPFOX || potential == PotType::BOP) {
 534→      LogPotential = true;
 535→    } else {
 536→      LogPotential = false;
 537→    }
 538→    LogPotential = ini.GetValueB("Potential", "log_potential", LogPotential);
 539→
 540→    // [AMS]
 541→    if (potential == PotType::AMS) {
 542→      ams_options.engine = ini.GetValue("AMS", "engine", ams_options.engine);
 543→      ams_options.forcefield =
 544→          ini.GetValue("AMS", "forcefield", ams_options.forcefield);
 545→      ams_options.resources =
 546→          ini.GetValue("AMS", "resources", ams_options.resources);
 547→      ams_options.model = ini.GetValue("AMS", "model", ams_options.model);
 548→      ams_options.xc = ini.GetValue("AMS", "xc", ams_options.xc);
 549→      ams_options.basis = ini.GetValue("AMS", "basis", ams_options.basis);
 550→    }
 551→    // [AMS_IO]
 552→    if (potential == PotType::AMS_IO) {
 553→      ams_options.engine =
 554→          ini.GetValue("AMS_IO", "engine", ams_options.engine);
 555→      ams_options.forcefield =
 556→          ini.GetValue("AMS_IO", "forcefield", ams_options.forcefield);
 557→      ams_options.model = ini.GetValue("AMS_IO", "model", ams_options.model);
 558→      ams_options.xc = ini.GetValue("AMS_IO", "xc", ams_options.xc);
 559→    }
 560→    // [AMS_ENV]
 561→    // This is only needed if the regular calls do not work
 562→    // e.g. on a MacOS machine
 563→    if (potential == PotType::AMS_IO || potential == PotType::AMS) {
 564→      ams_options.env.amshome =
 565→          ini.GetValue("AMS_ENV", "amshome", ams_options.env.amshome);
 566→      ams_options.env.scm_tmpdir =
 567→          ini.GetValue("AMS_ENV", "scm_tmpdir", ams_options.env.scm_tmpdir);
 568→      ams_options.env.scmlicense =
 569→          ini.GetValue("AMS_ENV", "scmlicense", ams_options.env.scmlicense);
 570→      ams_options.env.scm_pythondir = ini.GetValue(
 571→          "AMS_ENV", "scm_pythondir", ams_options.env.scm_pythondir);
 572→      ams_options.env.amsbin =
 573→          ini.GetValue("AMS_ENV", "amsbin", ams_options.env.amsbin);
 574→      ams_options.env.amsresources =
 575→          ini.GetValue("AMS_ENV", "amsresources", ams_options.env.amsresources);
 576→    }
 577→    // [XTBPot]
 578→    if (potential == PotType::XTB) {
 579→      xtb_options.paramset =
 580→          ini.GetValue("XTBPot", "paramset", xtb_options.paramset);
 581→      xtb_options.acc = ini.GetValueF("XTBPot", "accuracy", xtb_options.acc);
