 621→    }
 622→
 623→    // [Debug] //
 624→
 625→    debug_options.write_movies =
 626→        ini.GetValueB("Debug", "write_movies", debug_options.write_movies);
 627→    debug_options.write_movies_interval = ini.GetValueL(
 628→        "Debug", "write_movies_interval", debug_options.write_movies_interval);
 629→    debug_options.estimate_neb_eigenvalues = ini.GetValueB(
 630→        "Debug", "estimate_neb_eigenvalues",
 631→        debug_options.estimate_neb_eigenvalues);
 632→    debug_options.neb_mmf = toLowerCase(
 633→        ini.GetValue("Debug", "neb_mmf_estimator", debug_options.neb_mmf));
 634→
 635→    // [Structure Comparison] //
 636→
 637→    structure_comparison_options.distance_difference =
 638→        ini.GetValueF("Structure Comparison", "distance_difference",
 639→                      structure_comparison_options.distance_difference);
 640→    structure_comparison_options.neighbor_cutoff =
 641→        ini.GetValueF("Structure Comparison", "neighbor_cutoff",
