Parameters::Parameters() {

  kB = 8.6173324e-5;     // eV/K
  timeUnit = 10.1805055; // fs

  // [Main] //
  job = JobType::Process_Search;
  randomSeed = -1;
  temperature = 300.0;
  checkpoint = false;
  quiet = false;
  writeLog = true;
  iniFilename = "config.ini";
  conFilename = "pos.con";
  finiteDifference = 0.01;
  maxForceCalls = 0;
  removeNetForce = true;

  // [Prefactor] //
