  debug_options.estimate_neb_eigenvalues = false;
  debug_options.neb_mmf = LowestEigenmode::MINMODE_DIMER;

  // [Saddle Search] //
  saddle_search_options.displace_type = EpiCenters::DISP_LOAD;
