  // [Temperature Accelerated Dynamics] //
  tad_options.low_temperature = 300.0;
  tad_options.min_prefactor = 0.001;
  tad_options.confidence = 0.001;

  // [Replica Exchange] //
  replica_exchange_options.temperature_distribution = "exponential";
