class Parameters {

public:
  Parameters();
  ~Parameters() = default;
  // TODO: Is this complete?
  Parameters(const Parameters &) = default;
  int load(string filename);
  int load(FILE *file);

  /** string constants: declared here, defined in Parameters.cpp. **/

  // potentials //
  // jobs //

  // Physical Constants
  struct constants_t {
    double kB;
    double timeUnit;
  } constants;

  /** input parameters **/

  // [Main] //
  struct main_options_t {
    JobType job;
    long randomSeed;
    double temperature;
    bool quiet;
    bool writeLog;
    bool checkpoint;
    string iniFilename;
    string conFilename;
    double finiteDifference;
    long maxForceCalls;
    bool removeNetForce;
  } main_options;

  // [Potential] //
  struct potential_options_t {
    PotType potential;
    double MPIPollPeriod;
    bool LAMMPSLogging;
    int LAMMPSThreads;
    bool EMTRasmussen;
    bool LogPotential;
    string extPotPath;
    int MPIPotentialRank;
#ifdef EONMPI
    MPI_Comm MPIClientComm;
#endif
  } potential_options;

  // [AMS] and [AMS_IO] //
  struct ams_options_t {
    string engine;     // MOPAC, ADF, BAND, REAXFF, FORCEFIELD
    string forcefield; // OPt.ff etc. (REAXFF)
    string model;      // Model hamiltonian (MOPAC)
    string resources;  // DFTB
    string xc;         // Exchange (BAND, ADF)
    string basis;      // Basis (BAND, ADF)
    struct env_t {
      string amshome;
      string scm_tmpdir;
      string scmlicense;
      string scm_pythondir;
      string amsbin;
      string amsresources;
    } env;
  } ams_options;

  // [XTBPot] //
  struct xtb_options_t {
    string paramset;
    double elec_temperature;
    size_t maxiter;
    double acc;
    double charge;
    int uhf;
  } xtb_options;

